import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        Map<Integer, List<long[]>> adj = new HashMap<>();
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            adj.computeIfAbsent(u, key -> new ArrayList<>()).add(new long[]{v, cost});
        }

        PriorityQueue<long[]> maxHeap = new PriorityQueue<>((a, b) -> Long.compare(b[0], a[0]));
        maxHeap.offer(new long[]{Long.MAX_VALUE, 0, 0});

        long maxScore = -1;

        while (!maxHeap.isEmpty()) {
            long[] current = maxHeap.poll();
            long currentMinCost = current[0];
            long totalCost = current[1];
            int u = (int) current[2];

            if (u == n - 1) {
                if (totalCost <= k) {
                    if (currentMinCost > maxScore) {
                        maxScore = currentMinCost;
                    }
                }
                continue;
            }

            if (adj.containsKey(u)) {
                for (long[] edge : adj.get(u)) {
                    int v = (int) edge[0];
                    long cost = edge[1];
                    if (!online[v] && v != n - 1) {
                        continue;
                    }
                    long newTotal = totalCost + cost;
                    if (newTotal > k) {
                        continue;
                    }
                    long newMin = Math.min(currentMinCost, cost);
                    maxHeap.offer(new long[]{newMin, newTotal, v});
                }
            }
        }

        return maxScore;
    }
}
