import heapq
from collections import defaultdict

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = defaultdict(list)
    for u, v, cost in edges:
        adj[u].append((v, cost))

    max_heap = []
